import React, { CSSProperties, ReactElement, useState, useRef, useEffect } from 'react'
import { MoonLoader } from 'react-spinners'

import { Navigator } from '../navigation/Navigator'
import { useColors } from '../page_template/colors'
import { zIndex } from '../utils/zIndex'

export function GenericSearchBox<T>(
    props: {
        matches: T[]
        doSearch: (sq: string) => Promise<T[]>
        onChange?: (inp: T) => void
        link?: (inp: T) => ReturnType<Navigator['link']> | undefined
        onFocus?: () => void
        onBlur?: () => void
        onTextPresenceChange?: (hasText: boolean) => void
        autoFocus: boolean
        placeholder: string
        style: CSSProperties | string
        renderMatch: (currentMatch: () => T, onMouseOver: () => void, onClick: () => void, style: CSSProperties, dataTestId: string | undefined) => ReactElement
        allowEmptyQuery?: boolean
        loadingStatus?: string
    }): ReactElement {
    const colors = useColors()

    const [query, setQuery] = useState('')
    const queryRef = useRef('')

    const [focused, setFocused] = React.useState(0)
    const [matches, setMatches] = useState<T[]>([])

    const [isFocused, setIsFocused] = useState(false)
    const searchboxRef = useRef<HTMLInputElement>(null)

    const searchQuery = queryRef.current

    const reset = (): void => {
        // blur the input if we allow empty queries
        if (props.allowEmptyQuery) {
            searchboxRef.current?.blur()
            setIsFocused(false)
        }
        setQuery('')
        queryRef.current = ''
        setMatches([])
        setFocused(0)
        props.onTextPresenceChange?.(false)
    }

    const searchboxDropdownItemStyle = (idx: number): CSSProperties => {
        return {
            padding: '0.5em',
            cursor: 'pointer',
            backgroundColor: (focused === idx) ? colors.slightlyDifferentBackgroundFocused : undefined,
        }
    }

    const onFormSubmit = (event: React.FormEvent): boolean => {
        event.preventDefault()
        const terms = matches
        if (terms.length > 0) {
            void props.link?.(terms[focused])?.onClick()
            props.onChange?.(terms[focused])
            reset()
        }
        return false
    }

    const onTextBoxKeyUp = (event: React.KeyboardEvent<HTMLInputElement>): void => {
        // if down arrow, then go to the next one
        if (matches.length > 0) {
            if (event.key === 'ArrowDown') {
                setFocused((focused + 1) % matches.length)
            }
            if (event.key === 'ArrowUp') {
                setFocused((focused - 1) % matches.length)
            }
        }
    }

    const doSearch = props.doSearch

    // Do the search
    useEffect(() => {
        void (async () => {
            if ((props.allowEmptyQuery && !isFocused) || (!props.allowEmptyQuery && searchQuery === '')) {
                setMatches([])
                setFocused(0)
                return
            }

            const result = await doSearch(searchQuery)

            // we should throw away the result if the query has changed since we submitted the search
            if (queryRef.current !== searchQuery) {
                return
            }

            setMatches(result)
            setFocused(f => Math.max(0, Math.min(f, result.length - 1)))
        })()
    }, [searchQuery, doSearch, props.allowEmptyQuery, isFocused])

    return (
        <form
            autoComplete="off"
            style={{ marginBlockEnd: '0em', position: 'relative', width: '100%' }}
            onSubmit={onFormSubmit}
        >
            <input
                autoFocus={props.autoFocus}
                id="searchbox"
                type="text"
                className={typeof props.style === 'string' ? props.style : 'serif'}
                style={{
                    ...(typeof props.style === 'string' ? {} : props.style),
                }}
                placeholder={props.placeholder}
                onKeyUp={onTextBoxKeyUp}
                onChange={(e) => {
                    const newValue = e.target.value
                    setQuery(newValue)
                    queryRef.current = newValue
                    props.onTextPresenceChange?.(newValue.length > 0)
                }}
                value={query}
                onFocus={() => {
                    setIsFocused(true)
                    props.onFocus?.()
                }}
                onBlur={() => {
                    // allow people to click on stuff
                    void setTimeout(() => {
                        if (document.activeElement !== searchboxRef.current) {
                            setIsFocused(false)
                            props.onBlur?.()
                        }
                    }, 200)
                }}
                spellCheck={false}
                ref={searchboxRef}
            />

            <div
                style={{
                    position: 'absolute',
                    width: '100%',
                    maxHeight: '20em',
                    overflowY: 'auto',
                    backgroundColor: colors.slightlyDifferentBackground,
                    borderRadius: '0.25em',
                    zIndex: zIndex.searchResults,
                }}
            >
                {isFocused && matches.map((_, idx) => (
                    props.renderMatch(
                        () => matches[idx],
                        () => { setFocused(idx) },
                        () => {
                            props.onChange?.(matches[idx])
                            reset()
                        },
                        searchboxDropdownItemStyle(idx),
                        idx === focused ? 'selected-search-result' : undefined,
                    )
                ),
                )}
            </div>

            {/* When the user has typed a query, show them what's going on */}
            {isFocused && query.length > 0 && props.loadingStatus && <LoadingIndicator type={matches.length === 0 ? 'dropdown' : 'field'} message={props.loadingStatus} />}
        </form>
    )
}

function LoadingIndicator({ type, message }: { type: 'dropdown' | 'field', message: string }): ReactElement {
    const colors = useColors()

    switch (type) {
        case 'field':
            return (
                <div
                    style={{
                        position: 'absolute',
                        right: '0.5em',
                        top: 0,
                        bottom: 0,
                        display: 'flex',
                        alignItems: 'center',
                    }}
                    data-test-id="search-load-field"
                >
                    <MoonLoader color={colors.textMain} size="24px" />
                </div>
            )
        case 'dropdown':
            return (
                <div
                    style={{
                        color: colors.ordinalTextColor,
                        padding: '0.5em',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.5em',
                        borderRadius: '0.25em',
                        backgroundColor: colors.slightlyDifferentBackground,
                        zIndex: zIndex.searchResults,
                        position: 'absolute',
                        width: '100%',
                    }}
                    data-test-id="search-load-dropdown"
                >
                    <MoonLoader color={colors.textMain} size="20px" />
                    {message}
                </div>
            )
    }
}
